// frontend/src/components/Navbar.tsx
import React from 'react';
import { useNavigate, Link } from 'react-router-dom';

const Navbar = () => {
  const navigate = useNavigate();
  const userStr = localStorage.getItem('user');
  const user = userStr ? JSON.parse(userStr) : null;

  const handleLogout = () => {
    localStorage.removeItem('user');
    navigate('/login');
  };

  if (!user) return null;

  return (
    <nav className="bg-slate-900 border-b border-slate-800 sticky top-0 z-50 shadow-lg shadow-slate-900/20">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">

          {/* Logo Bölümü */}
          <div className="flex items-center">
            <Link 
              to="/" 
              className="flex items-center gap-2 text-white hover:text-blue-400 transition-colors group"
            >
              <div className="bg-blue-600 p-1.5 rounded-lg group-hover:bg-blue-500 transition-colors">
                <span className="text-lg">📚</span>
              </div>
              <span className="text-xl font-black tracking-tight">
                Kitabevi <span className="text-blue-500">Demo</span>
              </span>
            </Link>
          </div>

          {/* Navigasyon ve Profil */}
          <div className="flex items-center gap-6">
            <div className="hidden md:flex items-center gap-6 border-r border-slate-700 pr-6 mr-2">
              {user.role === 'admin' ? (
                <Link 
                  to="/admin" 
                  className="text-sm font-bold text-slate-300 hover:text-white transition-colors"
                >
                  Yönetici Paneli
                </Link>
              ) : (
                <Link 
                  to="/store" 
                  className="text-sm font-bold text-slate-300 hover:text-white transition-colors"
                >
                  Kitap Mağazası
                </Link>
              )}
            </div>

            {/* Kullanıcı Bilgisi */}
            <div className="flex items-center gap-4">
              <div className="flex flex-col items-end">
                <span className="text-[10px] uppercase tracking-widest text-slate-500 font-bold leading-none">
                  {user.role}
                </span>
                <span className="text-sm font-bold text-slate-200">
                  {user.username}
                </span>
              </div>

              {/* Çıkış Butonu */}
              <button 
                onClick={handleLogout}
                className="bg-red-500/10 hover:bg-red-500 text-red-500 hover:text-white border border-red-500/20 hover:border-red-500 px-4 py-2 rounded-xl text-xs font-black uppercase tracking-wider transition-all active:scale-95"
              >
                Çıkış
              </button>
            </div>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
